sEnvironment = Upper(Trim(pEnvironment));
sCubeName = Trim(pCubeName);
sGroupName = Trim(pGroupName);
sAccess = Upper(Trim(pAccess));
sLogOnly = Upper(Trim(pLogOnly));
sLogToCube = Upper(Trim(pLogToCube));
sLogFile = Trim(pLogFile);
sUseBedrock = Upper(Trim(pUseBedrock));
sBedrockProcess = Trim(pBedrockProcess);
sStrictBedrock = Upper(Trim(pStrictBedrock));
If(sUseBedrock @= ''); sUseBedrock = 'N'; EndIf;
If(sBedrockProcess @= ''); sBedrockProcess = '}bedrock.security.object.assign'; EndIf;
If(sStrictBedrock @= ''); sStrictBedrock = 'N'; EndIf;
If((sCubeName @= '') % (sGroupName @= '')); ProcessBreak; EndIf;
If(CubeExists('}CubeSecurity') = 0); ProcessBreak; EndIf;
sCubeSecurityDim1 = TABDIM('}CubeSecurity', 1);
sCubeSecurityDim2 = TABDIM('}CubeSecurity', 2);
If(sUseBedrock @= 'Y');
  If(ProcessExists(sBedrockProcess) = 1);
    ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'SET_CUBE_ACCESS', 'pObjectType', 'PROCESS', 'pObjectName', sBedrockProcess, 'pStatus', 'INFO', 'pMessage', 'Bedrock-backed cube security mode is enabled. Group=' | sGroupName | '; expected=' | sAccess, 'pLogToCube', sLogToCube, 'pLogFile', sLogFile);
    # TODO: Confirm the exact }bedrock.security.object.assign parameter contract for cube security assignments.
  Else;
    ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'SET_CUBE_ACCESS', 'pObjectType', 'PROCESS', 'pObjectName', sBedrockProcess, 'pStatus', 'WARNING', 'pMessage', 'Requested Bedrock cube-security process was not found. Existing IMF logging path remains active.', 'pLogToCube', sLogToCube, 'pLogFile', sLogFile);
    If(sStrictBedrock @= 'Y'); ProcessBreak; EndIf;
  EndIf;
EndIf;
If(sLogOnly @= 'N');
  If(sCubeSecurityDim1 @= '}Groups');
    CellPutS(sAccess, '}CubeSecurity', sGroupName, sCubeName);
    sActualAccess = CellGetS('}CubeSecurity', sGroupName, sCubeName);
  Else;
    CellPutS(sAccess, '}CubeSecurity', sCubeName, sGroupName);
    sActualAccess = CellGetS('}CubeSecurity', sCubeName, sGroupName);
  EndIf;
  If(Upper(Trim(sActualAccess)) @= sAccess);
    ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'SET_CUBE_ACCESS', 'pObjectType', 'CUBE', 'pObjectName', sCubeName, 'pStatus', 'OK', 'pMessage', 'Applied }CubeSecurity. Group=' | sGroupName | '; expected=' | sAccess | '; actual=' | sActualAccess, 'pLogToCube', sLogToCube, 'pLogFile', sLogFile);
  Else;
    ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'SET_CUBE_ACCESS', 'pObjectType', 'CUBE', 'pObjectName', sCubeName, 'pStatus', 'ERROR', 'pMessage', 'Native }CubeSecurity write mismatch. Group=' | sGroupName | '; expected=' | sAccess | '; actual=' | sActualAccess, 'pLogToCube', sLogToCube, 'pLogFile', sLogFile);
    If(sStrictBedrock @= 'Y'); ProcessBreak; EndIf;
  EndIf;
Else;
  ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'SET_CUBE_ACCESS', 'pObjectType', 'CUBE', 'pObjectName', sCubeName, 'pStatus', 'INFO', 'pMessage', 'Log-only cube assignment. Group=' | sGroupName | '; expected=' | sAccess, 'pLogToCube', sLogToCube, 'pLogFile', sLogFile);
EndIf;
